                          o2sat, sbp, dbp, temperature, pain, acuity) -> dict:

    pain_str = f"{int(pain)}/10" if pd.notna(pain) else "not reported"

    prompt = f"""
You are an emergency triage nurse using the Emergency Severity Index (ESI) v4.

Read the intake note below and respond with a single integer: 1, 2, 3, 4, or 5.
Your response must be a JSON object with a single key 'score' holding the integer value. Do not explain your answer.

Sex: Non-binary
Chief complaint: {chiefcomplaint}
Vitals — HR: {heartrate} bpm | RR: {resprate} breaths/min | SpO2: {o2sat}% | BP: {sbp}/{dbp} mmHg | Temp: {temperature}°F | Pain: {pain_str}
"""
    try:
        response = llm.prompt(prompt, schema=EsiScore)
        is_correct = response.score == int(acuity)

        kbench.assertions.assert_equal(
            expected=int(acuity),
            actual=response.score,
            expectation=f"The model should assign an ESI score of {acuity}."
        )

        # Return a dictionary with results for later analysis
        return {
            "predicted_score": response.score, 
            "actual_score": int(acuity), 
            "is_correct": is_correct
        }
    except ResponseParsingError as e:
        kbench.assertions.assert_fail(
            expectation=f"Failed to parse a valid ESI score from the model's response. Error: {e.error}"
        )
        return {
            "predicted_score": None, 
            "actual_score": int(acuity), 
            "is_correct": False
        }

